// Client executes federation operations. Use NewClient or NewClientWithHTTPFactory
// for simple cases; use NewClientWithFactories for webapp-style per-request URL
// resolution via service discovery.
type Client struct {
	httpFor    func(context.Context) *http.Client
	resolveFor func(ctx context.Context, specJSON string) (*Plan, error)
}

// NewClient builds the federation client with a fixed HTTP client and static
// subgraph URLs. subgraphURLs maps join__Graph enum names (e.g. "USERS") to their
// actual HTTP endpoints. All enum names referenced by any operation must be present;
// missing entries are caught at construction time.
func NewClient(httpClient *http.Client, subgraphURLs map[string]string) (FederationClient, error) {
	if httpClient == nil {
		httpClient = http.DefaultClient
	}
	return NewClientWithHTTPFactory(func(_ context.Context) *http.Client { return httpClient }, subgraphURLs)
}

