// NewClientWithFactories builds the federation client with per-call factories for
// both the HTTP client and plan resolution. Use this when subgraph URLs must be
// resolved per-request (e.g. from a context-aware service-discovery client).
// resolveFor receives the full operation's plan-spec JSON and must return a resolved
// Plan; it may call Resolve(specJSON, urls) with URLs fetched from the context.
// Unlike NewClient, this constructor does not validate plans at construction time.
func NewClientWithFactories(
	httpFactory func(context.Context) *http.Client,
	resolveFor func(ctx context.Context, specJSON string) (*Plan, error),
) FederationClient {
	if httpFactory == nil {
		httpFactory = func(_ context.Context) *http.Client { return http.DefaultClient }
	}
	return &Client{httpFor: httpFactory, resolveFor: resolveFor}
}

